# --- plot helper (hidden) — modular powers bounce unpredictably ---
# The curve is the student's OWN power_mod at each secret. Falls back to Python's
# built-in pow until power_mod works.
def __plot(g, p):
    try:
        pts = [[x, power_mod(g, x, p)] for x in range(1, p)]   # <- the STUDENT's function
        if pts and all(isinstance(pt[1], int) for pt in pts):
            return [{"name": "g^secret mod p (your code)", "points": pts, "highlight": True}]
    except Exception:
        pass
    pts = [[x, pow(g, x, p)] for x in range(1, p)]
    return [{"name": "g^secret mod p", "points": pts, "highlight": True}]
